protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator" — keep the old name so they remain readable
        // and direct SQL queries (e.g. WHERE c.Discriminator = 'Product') continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Existing documents have id format "Product|123" — keep the old format
        // so FindAsync and point-reads still resolve existing documents.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

